/**
 * @name Path traversal via taint from HTTP request to File/Path construction
 * @description Tainted data from HTTP request flows to file system operations without proper validation
 * @kind path-problem
 * @problem.severity error
 * @id java/path-traversal-http-to-file
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module PathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Paths.get
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // FileInputStream constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // ClassLoader.getResource / getResourceAsStream
    exists(MethodCall mc |
      (mc.getMethod().hasName("getResource") or mc.getMethod().hasName("getResourceAsStream")) and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module PathTraversalFlow = TaintTracking::Global<PathTraversalConfig>;
import PathTraversalFlow::PathGraph

from PathTraversalFlow::PathNode source, PathTraversalFlow::PathNode sink
where PathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Path traversal: HTTP input $@ flows to file system operation.", source.getNode(), "user input"

/**
 * @name Path traversal in FileResourceManager - containment check before canonicalization
 * @description FileResourceManager performs startsWith() containment check before getCanonicalFile(),
 *              allowing an attacker to bypass the check with path traversal sequences like ../
 * @kind path-problem
 * @problem.severity error
 * @id java/file-resource-manager-path-traversal-bypass
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

// Model the getRelativePath/path parameter in FileResourceManager.getResource
module FileResourceManagerConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Source: the path parameter of FileResourceManager.getResource
    exists(Method m |
      m.hasName("getResource") and
      m.getDeclaringType().hasQualifiedName("io.undertow.server.handlers.resource", "FileResourceManager") and
      source.asParameter() = m.getParameter(0)
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: the argument to new File(...) that uses the path before canonicalization
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // Or getCanonicalFile/getCanonicalPath calls
    exists(MethodCall mc |
      (mc.getMethod().hasName("getCanonicalFile") or mc.getMethod().hasName("getCanonicalPath")) and
      sink.asExpr() = mc.getQualifier()
    )
  }
}

module FileResourceManagerFlow = TaintTracking::Global<FileResourceManagerConfig>;
import FileResourceManagerFlow::PathGraph

from FileResourceManagerFlow::PathNode source, FileResourceManagerFlow::PathNode sink
where FileResourceManagerFlow::flowPath(source, sink)
select sink.getNode(), source, sink,
  "Path from FileResourceManager.getResource parameter $@ reaches file operation before proper canonicalization.",
  source.getNode(), "path parameter"

/**
 * @name ClassPathResourceManager - path traversal via ClassLoader
 * @description ClassPathResourceManager passes user path to ClassLoader.getResource() without checking for '..' sequences enabling path traversal to sensitive classpath resources
 * @kind path-problem
 * @problem.severity error
 * @id java/classpath-resource-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

// Model ClassPathResourceManager.getResource(path) as a source of tainted path input
class ClassPathResourceManagerGetResource extends Method {
  ClassPathResourceManagerGetResource() {
    this.hasName("getResource") and
    this.getDeclaringType().hasQualifiedName("io.undertow.server.handlers.resource", "ClassPathResourceManager")
  }
}

module ClasspathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Parameter of getResource in ClassPathResourceManager
    exists(ClassPathResourceManagerGetResource m |
      source.asParameter() = m.getAParameter()
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassLoader.getResource(path)
    exists(MethodCall mc |
      mc.getMethod().hasName("getResource") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // ClassLoader.getResourceAsStream(path)
    exists(MethodCall mc |
      mc.getMethod().hasName("getResourceAsStream") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module ClasspathTraversalFlow = TaintTracking::Global<ClasspathTraversalConfig>;
import ClasspathTraversalFlow::PathGraph

from ClasspathTraversalFlow::PathNode source, ClasspathTraversalFlow::PathNode sink
where ClasspathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink,
  "ClassPathResourceManager passes path $@ to ClassLoader.getResource() without checking for '..' path traversal sequences, potentially exposing sensitive classpath resources like WEB-INF/.",
  source.getNode(), "user-controlled path"

/**
 * @name FileResourceManager - path traversal: startsWith check before canonicalization
 * @description FileResourceManager.getResource() performs String.startsWith() containment check BEFORE calling getCanonicalFile(), allowing path traversal bypass
 * @kind path-problem
 * @problem.severity error
 * @id java/file-resource-manager-traversal-bypass
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

class FileResourceManagerGetResource extends Method {
  FileResourceManagerGetResource() {
    this.hasName("getResource") and
    this.getDeclaringType().hasQualifiedName("io.undertow.server.handlers.resource", "FileResourceManager")
  }
}

module FileResourceTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(FileResourceManagerGetResource m |
      source.asParameter() = m.getAParameter()
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // new File(base, path) - the File constructor call using user path
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module FileResourceTraversalFlow = TaintTracking::Global<FileResourceTraversalConfig>;
import FileResourceTraversalFlow::PathGraph

from FileResourceTraversalFlow::PathNode source, FileResourceTraversalFlow::PathNode sink
where FileResourceTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink,
  "FileResourceManager.getResource() flows path $@ into File constructor. The String.startsWith() containment check at line 83 occurs BEFORE getCanonicalFile() at line 94, allowing path traversal bypass.",
  source.getNode(), "user-controlled path parameter"
